import { nanoid } from 'nanoid'
model.id = nanoid() //=> "V1StGXR8_Z5jdHi6B-myT"

export default function createItems(arr){
    const item = arr.map(({name,country,born, died}) => {
        return`<li class="item" id="${nanoid(5)}">
    <h2 class="title">${name}</h2>
    <h3>${country}</h3>
    <p>${died}</p>
    <p>${born}</p>
    <p></p>
</li>`
    }).join("")
    return item
}